<?php
use App\Models\WebhookEvent;use Illuminate\Http\Request;use Illuminate\Support\Facades\Route;Route::post('/razorpay/webhook',function(Request $request){WebhookEvent::create(['source'=>'razorpay','event_id'=>$request->header('x-razorpay-event-id'),'event_name'=>$request->input('event'),'signature_valid'=>true,'headers'=>$request->headers->all(),'payload'=>$request->all(),'processing_status'=>'received']);return response()->json(['status'=>true]);});Route::post('/provider/webhook',function(Request $request){WebhookEvent::create(['source'=>'provider','event_id'=>$request->input('event_id'),'event_name'=>$request->input('event'),'signature_valid'=>true,'headers'=>$request->headers->all(),'payload'=>$request->all(),'processing_status'=>'received']);return response()->json(['status'=>true]);});
